import { ExternalTokenizer } from "@lezer/lr"
import * as Terms from "./parser.terms.js"

// 解构需要的 Terms
const { UnderlineText, StrikeText, Hr, ModuleBlock, ModuleOpenTag, ModuleContent, ModuleCloseTag } = Terms

// 字符常量定义
const _ = 95,
      dash = 45,
      newline = 10,
      carriageReturn = 13,
      bracketOpen = 91,  // [
      bracketClose = 93, // ]
      slash = 47,        // /
      space = 32;        // 空格

// 辅助函数：匹配字符串
function matchString(input, offset, str) {
  for (let i = 0; i < str.length; i++) {
    if (input.peek(offset + i) !== str.charCodeAt(i)) return false;
  }
  return true;
}

// 这里的常量你已经定义好了：bracketOpen=91, bracketClose=93, slash=47

export const moduleTokenizer = new ExternalTokenizer((input, stack) => {
  if (input.next == bracketOpen && input.peek(1) == bracketOpen) {
    
    // 情况 A: 闭合标签 [[/module]]
    if (input.peek(2) == slash && matchString(input, 3, "module")) {
      let offset = 9; // [[/module 长度
      while (input.peek(offset) != -1 && input.peek(offset) != newline) {
        if (input.peek(offset) == bracketClose && input.peek(offset + 1) == bracketClose) {
          for (let i = 0; i < offset + 2; i++) input.advance();
          input.acceptToken(ModuleCloseTag);
          return;
        }
        offset++;
      }
    }
    
    // 情况 B: 开始标签 [[module ...]]
    if (matchString(input, 2, "module")) {
      let offset = 8; // [[module 长度
      while (input.peek(offset) != -1 && input.peek(offset) != newline) {
        if (input.peek(offset) == bracketClose && input.peek(offset + 1) == bracketClose) {
          for (let i = 0; i < offset + 2; i++) input.advance();
          input.acceptToken(ModuleOpenTag);
          return;
        }
        offset++;
      }
    }
  }
});

// 核心：吞噬内容的黑洞
export const moduleContentScanner = new ExternalTokenizer((input, stack) => {
  let start = input.pos;
  while (input.next != -1) {
    // 盯死结束信号：只要没看到 [[/module]] 就一直吃
    if (input.next == bracketOpen && 
        input.peek(1) == bracketOpen && 
        input.peek(2) == slash && 
        matchString(input, 3, "module")) {
      
      if (input.pos > start) {
        input.acceptToken(ModuleContent);
        return;
      }
      return; // 如果直接遇到闭合标签，内容为空
    }
    input.advance();
  }
  if (input.pos > start) input.acceptToken(ModuleContent);
});

export const inlineTokenizer = new ExternalTokenizer((input, stack) => {
  let next = input.next;

  // 1. 下划线逻辑: __...__
  if (next == _) {
    if (input.peek(1) == _) {
      let offset = 2;
      let hasContent = false;
      while (true) {
        let curr = input.peek(offset);
        if (curr == -1 || curr == newline || curr == carriageReturn) break;
        if (curr == _) {
          if (input.peek(offset + 1) == _) {
            if (hasContent) {
              for (let i = 0; i < offset + 2; i++) input.advance();
              input.acceptToken(UnderlineText);
              return;
            }
            break; 
          }
        }
        hasContent = true;
        offset++;
      }
    }
  }

  // 2. 连字号逻辑: 处理 Hr (分割线) 和 StrikeText (删除线)
  if (next == dash) {
    let count = 0;
    // 先数一数有多少个连续的 -
    while (input.peek(count) == dash) {
      count++;
    }

    // --- 情况 A: 水平分割线 (4个或更多 -) ---
    if (count >= 4) {
      for (let i = 0; i < count; i++) input.advance();
      input.acceptToken(Hr);
      return;
    }

    // --- 情况 B: 删除线 (--内容--) ---
    if (count == 2) {
      let offset = 2;
      let hasContent = false;
      
      while (true) {
        let curr = input.peek(offset);
        if (curr == -1 || curr == newline || curr == carriageReturn) break;
        
        if (curr == dash) {
          if (input.peek(offset + 1) == dash) {
            // 确保结尾恰好是两个 -，排除 --- 这种干扰
            if (input.peek(offset + 2) != dash) {
              if (hasContent) {
                for (let i = 0; i < offset + 2; i++) input.advance();
                input.acceptToken(StrikeText);
                return;
              }
            }
            break;
          }
        }
        hasContent = true;
        offset++;
      }
    }
    // 如果是 1个 或 3个 -，或者没有正确闭合，直接跳过，交给 grammar 处理
  }
});